    /** Execute a sequence of multiple actions (click, type, click) and verify all succeed with correct indices */
    public function test_interact_action_sequence(): void
    {
        $engine_config = CrawlConfig::from_json(json_encode(["browser" => ["mode" => "always"]]));
        $engine = Kreuzcrawl::createEngine($engine_config);
        $url = getenv('MOCK_SERVER_URL') . '/fixtures/interact_action_sequence';
        $result = Kreuzcrawl::interact($engine, $url, [["selector" => "#open", "type" => "click"], ["selector" => "#field", "text" => "test_data", "type" => "type"], ["selector" => "#submit", "type" => "click"]]);
        $this->assertEquals(0, $result->getActionResults()[0]->actionIndex);
        $this->assertEquals("click", trim($result->getActionResults()[0]->actionType));
        $this->assertEquals(true, $result->getActionResults()[0]->success);
        $this->assertEquals(1, $result->getActionResults()[1]->actionIndex);
        $this->assertEquals("type", trim($result->getActionResults()[1]->actionType));
        $this->assertEquals(true, $result->getActionResults()[1]->success);
        $this->assertEquals(2, $result->getActionResults()[2]->actionIndex);
        $this->assertEquals("click", trim($result->getActionResults()[2]->actionType));
        $this->assertEquals(true, $result->getActionResults()[2]->success);

    }


